/* Minimal local Three-like shim for FlowForm lightweight preview */
(function (global) {
  class Scene { constructor(){ this.children=[]; this.background=null; } add(o){ this.children.push(o);} }
  class Color { constructor(v){ this.value=v; } }
  class PerspectiveCamera { constructor(){ this.position={set(){}}; } }
  class WebGLRenderer { constructor(opts){ this.canvas=opts.canvas; this.domElement=opts.canvas; } setSize(){} render(){} }
  class Clock { getDelta(){ return 0.016; } }
  class HemisphereLight { constructor(){} }
  class DirectionalLight { constructor(){ this.position={set(){}}; } }
  class AnimationMixer { constructor(){ } clipAction(){ return { reset(){return this;}, fadeIn(){return this;}, play(){return this;}, stop(){return this;}, crossFadeTo(){return this;} }; } update(){} }
  global.THREE = { Scene, Color, PerspectiveCamera, WebGLRenderer, Clock, HemisphereLight, DirectionalLight, AnimationMixer };
})(window);
